PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT DISTINCT ?date
WHERE {
  ?homerun wdt:P31 wd:Q185830 ;
             wdt:P276 wd:Q6800607 ;
             wdt:P361 ?game ;
             wdt:P710 ?player .

  ?player wdt:P54 wd:Q308966 .

  ?game wdt:P710 wd:Q308966 ;
        wdt:P710 wd:Q692417 ;
        wdt:P276 wd:Q670219 ;
        wdt:P585 ?date .
}
LIMIT 10
